INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-education-samayik-for-beginners', 'education', 'samayik-for-beginners', 'Samayik for Beginners', 'Practice Path for Beginners', 'Practice Path for Beginners शुरुआती साधना मार्ग Samayik for Beginners सामायिक का शुरुआती परिचय Samayik This lesson does not attempt to teach the full formal procedure of Samayik. Instead, it introduces the practice as a discipline of stillness, reflection, and self-awareness. यह पाठ सामायिक के पूर्ण विधि-विधान नहीं बताता, बल्कि उसके शांत भाव, मनन और आत्म-अनुशासन के उद्देश्य का शुरुआती परिचय देता है। Intermediate', '/course-detail.html?slug=samayik-for-beginners', 'Intermediate', 'Samayik', 'en', 'published', 'verified', 'JainWorld', '2026-05-26', '2026-05-26', 4, '2026-05-26');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-education-pratikraman-overview', 'education', 'pratikraman-overview', 'Pratikraman overview', 'Practice Path for Beginners', 'Practice Path for Beginners शुरुआती साधना मार्ग Pratikraman overview प्रतिक्रमण का परिचय Pratikraman This lesson introduces Pratikraman through the themes of self-review, forgiveness, and restraint. Formal practice may require family, teacher, or traditional guidance. यह पाठ प्रतिक्रमण को आत्म-परीक्षण, क्षमा और संयम की भावना से जोड़कर समझाता है। औपचारिक अभ्यास के लिए परिवार, गुरु या पारंपरिक मार्गदर्शन आवश्यक हो सकता है। Intermediate', '/course-detail.html?slug=pratikraman-overview', 'Intermediate', 'Pratikraman', 'en', 'published', 'verified', 'JainWorld', '2026-05-26', '2026-05-26', 4, '2026-05-26');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-education-fasting-and-self-discipline', 'education', 'fasting-and-self-discipline', 'Fasting and self-discipline', 'Fasting and Self-Discipline', 'Fasting and Self-Discipline उपवास और संयम Fasting and self-discipline उपवास और आत्मसंयम Fasting This lesson views fasting not simply as a food change, but as a practice of awareness, restraint, and self-discipline. Families and traditions may follow different forms. यह पाठ उपवास को केवल भोजन परिवर्तन नहीं, बल्कि सजगता, सीमितता और आत्म-संयम की सीख के रूप में देखता है। परिवारों और परंपराओं में अभ्यास के रूप अलग हो सकते हैं। Intermediate', '/course-detail.html?slug=fasting-and-self-discipline', 'Intermediate', 'Fasting', 'en', 'published', 'verified', 'JainWorld', '2026-05-26', '2026-05-26', 4, '2026-05-26');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-education-jain-festivals-learning-path', 'education', 'jain-festivals-learning-path', 'Understanding Jain festivals', 'Jain Festivals Learning Path', 'Jain Festivals Learning Path जैन पर्व सीखने का मार्ग Understanding Jain festivals जैन पर्वों की शुरुआती समझ Festival Learning This lesson explains that Jain festivals are not only dates on a calendar, but occasions for study, forgiveness, austerity, restraint, and family remembrance. यह पाठ बताता है कि जैन पर्व केवल तिथियाँ नहीं, बल्कि अध्ययन, क्षमा, तप, संयम और पारिवारिक स्मरण के अवसर भी होते हैं। Beginner', '/course-detail.html?slug=jain-festivals-learning-path', 'Beginner', 'Festival Learning', 'en', 'published', 'verified', 'JainWorld', '2026-05-26', '2026-05-26', 4, '2026-05-26');
