INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-resources-jain-scholarship-guidance', 'resources', 'jain-scholarship-guidance', 'Jain scholarship guidance', 'A careful starting point for families and students who want to understand how to verify scholarship information without assuming current benefits or approval.', 'A careful starting point for families and students who want to understand how to verify scholarship information without assuming current benefits or approval. छात्रों और परिवारों के लिए एक सावधान प्रारंभिक मार्गदर्शिका, जिससे वे बिना अनुमान लगाए छात्रवृत्ति जानकारी की सत्यता जाँच सकें। Eligibility varies by provider, year, state, institution type, and current official notice. Helps students begin careful research before relying on secondary summaries. Use only the current official notice to confirm final document requirements. Scholarship India', '/resources.html', 'Scholarship', 'India', 'en', 'published', 'verified', 'JainWorld reviewed guide', '2026-05-26', '2026-05-26', 5, '2026-05-26');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-resources-minority-scholarship-document-checklist', 'resources', 'minority-scholarship-document-checklist', 'Minority scholarship document checklist', 'A practical pre-application checklist covering the kinds of documents many scholarship processes may request.', 'A practical pre-application checklist covering the kinds of documents many scholarship processes may request. आवेदन से पहले उपयोगी दस्तावेज़ों की एक व्यवहारिक सूची, जो कई छात्रवृत्ति प्रक्रियाओं में काम आ सकती है। Useful for students, parents, volunteers, and application helpers. Can reduce delays by helping families collect likely paperwork early. Photo ID, address proof, marksheets, bank details, income records, photographs, and institution documents may be required depending on the scheme. Documents / How-to Guide India', '/resources.html', 'Documents / How-to Guide', 'India', 'en', 'published', 'verified', 'JainWorld reviewed checklist', '2026-05-26', '2026-05-26', 5, '2026-05-26');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-resources-government-minority-resources-guide', 'resources', 'government-minority-resources-guide', 'Government minority resources guide', 'A cautious guide to identifying official portals, current notices, and the right authority before trusting a summary about a scheme.', 'A cautious guide to identifying official portals, current notices, and the right authority before trusting a summary about a scheme. किसी योजना के सारांश पर भरोसा करने से पहले आधिकारिक पोर्टल, वर्तमान नोटिस और सही प्राधिकरण पहचानने की सावधान मार्गदर्शिका। For anyone trying to verify whether a scheme or notice is official and current. Encourages users to depend on official notifications rather than assumptions. No fixed documents for this guide. Always use the relevant official notification. Government Scheme India', '/resources.html', 'Government Scheme', 'India', 'en', 'published', 'verified', 'JainWorld reviewed guide', '2026-05-26', '2026-05-26', 5, '2026-05-26');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-resources-jain-educational-institutions-directory-placeholder', 'resources', 'jain-educational-institutions-directory-placeholder', 'Jain educational institutions directory placeholder', 'A placeholder structure for future verified listings of Jain schools, colleges, libraries, pathshalas, and study centers.', 'A placeholder structure for future verified listings of Jain schools, colleges, libraries, pathshalas, and study centers. जैन विद्यालयों, महाविद्यालयों, पुस्तकालयों, पाठशालाओं और अध्ययन केंद्रों की भविष्य की सत्यापित सूची के लिए एक प्लेसहोल्डर संरचना। Useful for students, parents, and researchers exploring institution types. Supports future verified discovery without claiming complete or current listings today. Directory browsing does not require documents. Individual institutions may ask for their own admission materials. Educational Institution India', '/resources.html', 'Educational Institution', 'India', 'en', 'published', 'needs_review', 'Directory in progress', '2026-05-26', '2026-05-26', 5, '2026-05-26');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-resources-jain-hostels-and-dharamshala-directory-placeholder', 'resources', 'jain-hostels-and-dharamshala-directory-placeholder', 'Jain hostels and dharamshala directory placeholder', 'A placeholder for future verified city-wise references to Jain hostels, student accommodation, and dharamshala-related support.', 'A placeholder for future verified city-wise references to Jain hostels, student accommodation, and dharamshala-related support. जैन छात्रावास, छात्र आवास और धर्मशाला-संबंधी सहायता की भविष्य की सत्यापित नगर-वार सूची के लिए प्लेसहोल्डर। Availability depends on location, institution, and local rules. Helps users understand what kinds of entries JainWorld plans to verify over time. Please verify any hostel or stay-related requirements directly with the relevant office. Student Hostel India', '/resources.html', 'Student Hostel', 'India', 'en', 'published', 'needs_review', 'Directory in progress', '2026-05-26', '2026-05-26', 5, '2026-05-26');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-resources-jain-trusts-and-community-support-directory-placeholder', 'resources', 'jain-trusts-and-community-support-directory-placeholder', 'Jain trusts and community support directory placeholder', 'A safe placeholder for future verified listings of Jain trusts, charities, seva groups, and community support references.', 'A safe placeholder for future verified listings of Jain trusts, charities, seva groups, and community support references. जैन ट्रस्ट, चैरिटी, सेवा समूह और सामुदायिक सहायता संदर्भों की भविष्य की सत्यापित सूची के लिए सुरक्षित प्लेसहोल्डर। Support depends on the trust, location, and the type of help being requested. Sets expectations for future verified directory work without claiming completeness today. Any required documents will depend on the organization and support context. Jain Trust / NGO India / Global', '/resources.html', 'Jain Trust / NGO', 'India / Global', 'en', 'published', 'needs_review', 'Directory in progress', '2026-05-26', '2026-05-26', 5, '2026-05-26');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-resources-how-to-verify-official-scheme-links', 'resources', 'how-to-verify-official-scheme-links', 'How to verify official scheme links', 'A practical guide to checking whether a scheme link, notice, or portal is official before sharing it with students or families.', 'A practical guide to checking whether a scheme link, notice, or portal is official before sharing it with students or families. छात्रों या परिवारों के साथ साझा करने से पहले यह जांचने की व्यवहारिक मार्गदर्शिका कि कोई योजना लिंक, नोटिस या पोर्टल आधिकारिक है या नहीं। Useful for students, parents, volunteers, and resource curators. Reduces confusion and discourages reliance on outdated or unofficial pages. No fixed documents for this guide. Documents / How-to Guide India', '/resources.html', 'Documents / How-to Guide', 'India', 'en', 'published', 'verified', 'JainWorld reviewed guide', '2026-05-26', '2026-05-26', 5, '2026-05-26');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-resources-how-to-submit-a-resource-correction', 'resources', 'how-to-submit-a-resource-correction', 'How to submit a resource correction', 'A simple guide explaining what details help JainWorld review a resource update, broken link, or outdated note.', 'A simple guide explaining what details help JainWorld review a resource update, broken link, or outdated note. एक सरल मार्गदर्शिका जो बताती है कि संसाधन अपडेट, टूटा हुआ लिंक या पुरानी जानकारी भेजते समय कौन से विवरण उपयोगी होते हैं। Open to students, families, institutions, and volunteers who want to improve public resource quality. Helps the public corrections workflow stay clearer and more useful over time. Please include the page title, the issue noticed, and the best official source link if available. Documents / How-to Guide Global', '/resources.html', 'Documents / How-to Guide', 'Global', 'en', 'published', 'verified', 'JainWorld corrections workflow', '2026-05-26', '2026-05-26', 5, '2026-05-26');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-resources-student-support-resources', 'resources', 'student-support-resources', 'Student support resources', 'A broad reference entry covering the kinds of support students may look for, such as scholarships, hostels, study centers, and trusted guidance.', 'A broad reference entry covering the kinds of support students may look for, such as scholarships, hostels, study centers, and trusted guidance. एक व्यापक संदर्भ प्रविष्टि जिसमें छात्रवृत्ति, छात्रावास, अध्ययन केंद्र और विश्वसनीय मार्गदर्शन जैसे छात्र सहायता विषय शामिल हैं। Useful for students and guardians planning educational support research. Helps users think in categories before searching for specific verified sources. Documents vary by service and provider. Student Support India / Global', '/resources.html', 'Student Support', 'India / Global', 'en', 'published', 'curated', 'JainWorld learning reference', '2026-05-26', '2026-05-26', 5, '2026-05-26');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-resources-family-support-resources', 'resources', 'family-support-resources', 'Family support resources', 'A broad family-oriented reference for users seeking practical community, educational, and temple-linked support pathways.', 'A broad family-oriented reference for users seeking practical community, educational, and temple-linked support pathways. व्यावहारिक सामुदायिक, शैक्षणिक और मंदिर-संबंधी सहायता मार्ग खोजने वाले उपयोगकर्ताओं के लिए परिवार-केंद्रित संदर्भ प्रविष्टि। Useful for families, caregivers, volunteers, and community organizers. Supports safer planning by encouraging users to verify each official source before acting on it. Requirements vary by organization and service. Family Support India / Global', '/resources.html', 'Family Support', 'India / Global', 'en', 'published', 'curated', 'JainWorld learning reference', '2026-05-26', '2026-05-26', 5, '2026-05-26');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-calendar-cal-1', 'calendar', 'cal-1', 'Mahavir Jayanti', 'An important festival linked with the birth kalyanak of Bhagwan Mahavir and associated with study, devotion, and community remembrance. Please verify the exact date from a local Jain calendar.', 'Mahavir Jayanti महावीर जयंती An important festival linked with the birth kalyanak of Bhagwan Mahavir and associated with study, devotion, and community remembrance. Please verify the exact date from a local Jain calendar. भगवान महावीर के जन्म कल्याणक से जुड़ी श्रद्धा, अध्ययन और सामुदायिक स्मरण का महत्त्वपूर्ण पर्व। सटीक तिथि स्थानीय जैन कैलेंडर से सत्यापित करें। Sample festival date Festival Puja, study, discourse, and remembrance पूजा, स्वाध्याय, प्रवचन और स्मरण', '/calendar.html', 'Festival', 'Sample festival date', 'en', 'published', 'verified', 'JainWorld', '2026-04-03', '2026-04-03', 3, '2026-04-03');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-calendar-cal-2', 'calendar', 'cal-2', 'Paryushan', 'A deeply important festival period associated with self-reflection, study, austerity, forgiveness, and restraint. Dates may vary by year and tradition.', 'Paryushan पर्युषण A deeply important festival period associated with self-reflection, study, austerity, forgiveness, and restraint. Dates may vary by year and tradition. आत्मचिंतन, स्वाध्याय, तप, क्षमा और संयम के लिए जैन परिवारों में विशेष महत्त्व वाला पर्वकाल। तिथि परंपरा और वर्ष के अनुसार बदल सकती है। Verify locally Festival Pratikraman, study, austerity, and forgiveness-oriented observance प्रतिक्रमण, स्वाध्याय, तप और क्षमाभाव', '/calendar.html', 'Festival', 'Verify locally', 'en', 'published', 'verified', 'JainWorld', '2026-09-07', '2026-09-07', 3, '2026-09-07');
